import React from 'react';
import { Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Users, 
  FileText, 
  Brain, 
  Settings,
  GraduationCap,
  Home
} from 'lucide-react';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
import Students from './components/Students';
import Accomplishments from './components/Accomplishments';
import Predictions from './components/Predictions';
import ModelManagement from './components/ModelManagement';

// Layout component with sidebar for internal pages
function MainLayout({ children }) {
  const location = useLocation();

  const navItems = [
    { path: '/dashboard', icon: LayoutDashboard, label: 'Dashboard' },
    { path: '/students', icon: Users, label: 'Students' },
    { path: '/accomplishments', icon: FileText, label: 'Accomplishments' },
    { path: '/predictions', icon: Brain, label: 'PQF Predictions' },
    { path: '/models', icon: Settings, label: 'Model Management' },
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex">
      {/* Sidebar */}
      <aside className="w-64 bg-white shadow-lg">
        <div className="p-6">
          <div className="flex items-center space-x-3">
            <GraduationCap className="h-8 w-8 text-primary-600" />
            <div>
              <h1 className="text-xl font-bold text-gray-900">PQF Predictor</h1>
              <p className="text-xs text-gray-500">OJT Classification System</p>
            </div>
          </div>
        </div>

        <nav className="mt-6 px-4">
          <Link
            to="/"
            className="flex items-center space-x-3 px-4 py-3 rounded-lg mb-1 text-gray-600 hover:bg-gray-50 hover:text-gray-900 transition-colors"
          >
            <Home className="h-5 w-5" />
            <span className="font-medium">Back to Home</span>
          </Link>
          <div className="border-t border-gray-200 my-3"></div>
          {navItems.map((item) => {
            const Icon = item.icon;
            const isActive = location.pathname === item.path;
            return (
              <Link
                key={item.path}
                to={item.path}
                className={`flex items-center space-x-3 px-4 py-3 rounded-lg mb-1 transition-colors ${
                  isActive 
                    ? 'bg-primary-50 text-primary-700' 
                    : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
                }`}
              >
                <Icon className="h-5 w-5" />
                <span className="font-medium">{item.label}</span>
              </Link>
            );
          })}
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto">
        {children}
      </main>
    </div>
  );
}

function App() {
  return (
    <Routes>
      {/* Landing Page - No Sidebar */}
      <Route path="/" element={<LandingPage />} />

      {/* Internal Pages - With Sidebar */}
      <Route path="/dashboard" element={<MainLayout><Dashboard /></MainLayout>} />
      <Route path="/students" element={<MainLayout><Students /></MainLayout>} />
      <Route path="/accomplishments" element={<MainLayout><Accomplishments /></MainLayout>} />
      <Route path="/predictions" element={<MainLayout><Predictions /></MainLayout>} />
      <Route path="/models" element={<MainLayout><ModelManagement /></MainLayout>} />
    </Routes>
  );
}

export default App;
